'use client';

import { useState } from 'react';
import Image from 'next/image';
import Link from 'next/link';
import {
  Lock,
  Eye,
  EyeOff,
  Download,
  Heart,
  Share2,
  Grid,
  LogOut,
  ArrowUpRight,
} from 'lucide-react';
import ScrollReveal from '@/components/ScrollReveal';

export default function ClientPortalPage() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [activeTab, setActiveTab] = useState<'all' | 'favorites'>('all');
  const [favorites, setFavorites] = useState<Set<number>>(new Set());

  const mockGallery = [
    'https://images.unsplash.com/photo-1519741497674-611481863552?w=600&q=80',
    'https://images.unsplash.com/photo-1606216794074-735e91aa2c92?w=600&q=80',
    'https://images.unsplash.com/photo-1583939003579-730e3918a45a?w=600&q=80',
    'https://images.unsplash.com/photo-1511285560929-80b456fea0bc?w=600&q=80',
    'https://images.unsplash.com/photo-1465495976277-4387d4b0b4c6?w=600&q=80',
    'https://images.unsplash.com/photo-1529636798458-92182e662485?w=600&q=80',
  ];

  const toggleFavorite = (index: number) => {
    setFavorites((prev) => {
      const next = new Set(prev);
      if (next.has(index)) next.delete(index);
      else next.add(index);
      return next;
    });
  };

  const displayedImages =
    activeTab === 'favorites'
      ? mockGallery.filter((_, i) => favorites.has(i))
      : mockGallery;

  /* ── Login Screen ── */
  if (!isLoggedIn) {
    return (
      <section className="min-h-screen flex items-center justify-center px-6 bg-bg pt-20">
        <ScrollReveal>
          <div className="max-w-md w-full">
            {/* Header */}
            <div className="text-center mb-10">
              <div className="w-16 h-16 rounded-2xl bg-bg-light border border-border flex items-center justify-center mx-auto mb-6">
                <Lock size={22} className="text-gold" />
              </div>
              <h1 className="font-serif text-4xl text-text-primary mb-2">
                Client <span className="italic text-gold">Portal</span>
              </h1>
              <p className="text-text-tertiary text-sm">
                Access your private photo galleries and downloads.
              </p>
            </div>

            {/* Form */}
            <form
              onSubmit={(e) => {
                e.preventDefault();
                setIsLoggedIn(true);
              }}
              className="space-y-5"
            >
              <div>
                <label className="text-text-tertiary text-xs tracking-wider uppercase mb-2 block">
                  Email
                </label>
                <input
                  type="email"
                  required
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="input-apple"
                  placeholder="your@email.com"
                />
              </div>

              <div>
                <label className="text-text-tertiary text-xs tracking-wider uppercase mb-2 block">
                  Gallery Password
                </label>
                <div className="relative">
                  <input
                    type={showPassword ? 'text' : 'password'}
                    required
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="input-apple pr-12"
                    placeholder="Enter gallery password"
                  />
                  <button
                    type="button"
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute right-4 top-1/2 -translate-y-1/2 text-text-tertiary hover:text-text-primary transition-colors"
                  >
                    {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
                  </button>
                </div>
              </div>

              <button
                type="submit"
                className="btn-primary w-full py-4 text-sm"
              >
                Access Gallery
                <ArrowUpRight size={14} />
              </button>
            </form>

            <p className="text-text-tertiary text-xs text-center mt-6">
              Your gallery password was sent via email after your session.
            </p>

            <div className="text-center mt-8">
              <Link
                href="/contact"
                className="text-gold text-xs tracking-wider uppercase hover:underline"
              >
                Need help? Contact us
              </Link>
            </div>
          </div>
        </ScrollReveal>
      </section>
    );
  }

  /* ── Gallery Dashboard ── */
  return (
    <>
      {/* Header */}
      <section className="bg-bg pt-32 pb-8 px-6">
        <div className="max-w-[1400px] mx-auto">
          <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-4">
            <div>
              <p className="text-gold text-[11px] tracking-[0.2em] uppercase font-medium mb-2">
                Welcome back
              </p>
              <h1 className="font-serif text-4xl md:text-5xl text-text-primary">
                Your <span className="italic text-gold">Gallery</span>
              </h1>
            </div>
            <div className="flex gap-2">
              <button className="btn-secondary px-5 py-2.5 text-xs inline-flex items-center gap-2">
                <Download size={14} /> Download All
              </button>
              <button className="btn-secondary px-5 py-2.5 text-xs inline-flex items-center gap-2">
                <Share2 size={14} /> Share
              </button>
              <button
                onClick={() => setIsLoggedIn(false)}
                className="px-4 py-2.5 text-xs text-text-tertiary hover:text-text-primary inline-flex items-center gap-2 transition-colors"
              >
                <LogOut size={14} /> Sign Out
              </button>
            </div>
          </div>
        </div>
      </section>

      {/* Filter tabs */}
      <div className="sticky top-[56px] z-30 bg-bg-white/80 backdrop-blur-xl border-b border-border">
        <div className="max-w-[1400px] mx-auto px-6 py-3 flex gap-2">
          <button
            onClick={() => setActiveTab('all')}
            className={`flex items-center gap-2 px-5 py-2 text-sm rounded-full transition-all duration-300 ${
              activeTab === 'all'
                ? 'bg-text-primary text-white font-medium'
                : 'text-text-secondary hover:text-text-primary'
            }`}
          >
            <Grid size={12} /> All Photos
          </button>
          <button
            onClick={() => setActiveTab('favorites')}
            className={`flex items-center gap-2 px-5 py-2 text-sm rounded-full transition-all duration-300 ${
              activeTab === 'favorites'
                ? 'bg-text-primary text-white font-medium'
                : 'text-text-secondary hover:text-text-primary'
            }`}
          >
            <Heart size={12} /> Favorites
            {favorites.size > 0 && (
              <span className="text-[10px] bg-gold text-white rounded-full w-5 h-5 flex items-center justify-center">
                {favorites.size}
              </span>
            )}
          </button>
        </div>
      </div>

      {/* Gallery Grid */}
      <section className="py-12 px-6 bg-bg min-h-[50vh]">
        <div className="max-w-[1400px] mx-auto">
          {displayedImages.length === 0 ? (
            <div className="text-center py-24">
              <Heart size={32} className="text-text-tertiary mx-auto mb-4" />
              <p className="text-text-secondary text-sm">
                No favorites yet. Click the heart icon on any photo to add it.
              </p>
            </div>
          ) : (
            <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
              {displayedImages.map((src, i) => {
                const realIndex = mockGallery.indexOf(src);
                return (
                  <ScrollReveal key={realIndex} delay={i * 0.05}>
                    <div className="group relative aspect-square overflow-hidden rounded-xl cursor-pointer transition-all duration-500 hover:shadow-lg hover:scale-[1.02]">
                      <Image
                        src={src}
                        alt={`Gallery photo ${realIndex + 1}`}
                        fill
                        className="object-cover transition-transform duration-700 group-hover:scale-105"
                        sizes="(max-width: 768px) 50vw, 33vw"
                      />
                      {/* Hover overlay */}
                      <div className="absolute inset-0 bg-black/0 group-hover:bg-black/20 transition-colors duration-500" />

                      {/* Action buttons */}
                      <div className="absolute top-3 right-3 flex gap-1.5 opacity-0 group-hover:opacity-100 transition-all duration-300">
                        <button
                          onClick={(e) => {
                            e.stopPropagation();
                            toggleFavorite(realIndex);
                          }}
                          className={`w-9 h-9 rounded-full bg-white/90 backdrop-blur-sm flex items-center justify-center transition-colors ${
                            favorites.has(realIndex)
                              ? 'text-gold'
                              : 'text-text-secondary hover:text-gold'
                          }`}
                        >
                          <Heart
                            size={14}
                            fill={favorites.has(realIndex) ? 'currentColor' : 'none'}
                          />
                        </button>
                        <button className="w-9 h-9 rounded-full bg-white/90 backdrop-blur-sm flex items-center justify-center text-text-secondary hover:text-text-primary transition-colors">
                          <Download size={14} />
                        </button>
                      </div>
                    </div>
                  </ScrollReveal>
                );
              })}
            </div>
          )}
        </div>
      </section>

      {/* Info Bar */}
      <section className="bg-bg-light py-16 px-6">
        <ScrollReveal>
          <div className="max-w-2xl mx-auto text-center">
            <h2 className="font-serif text-2xl md:text-3xl text-text-primary mb-3">
              Need More <span className="italic text-gold">Prints</span>?
            </h2>
            <p className="text-text-secondary text-sm mb-8 leading-relaxed">
              Visit our print store to order museum-quality prints, albums, and
              wall art from your gallery.
            </p>
            <Link
              href="/print-store"
              className="btn-primary inline-flex items-center gap-2 text-sm"
            >
              Browse Print Store
              <ArrowUpRight size={14} />
            </Link>
          </div>
        </ScrollReveal>
      </section>
    </>
  );
}
